    public static List<Block> blocks = new ArrayList<>();

    private static <T extends Block> T registerBlock(String id, T block) {
        Registry.register(BuiltInRegistries.BLOCK, Ubergrowth.id(id), block);
        Registry.register(BuiltInRegistries.ITEM, Ubergrowth.id(id), new BlockItem(block, new FabricItemSettings()));

        blocks.add(block);
        return block;
    }

